{"ideviceId":"idevice-1781029102279-qz4davjc4","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<style>
        /* ===================================================
           1. ESTILOS GLOBALES Y CONTADOR MATEMÁTICO SEGURO
           =================================================== */
        .exe-dg-wrapper {
            background-color: #fcfdfc;
            padding: 30px 10px;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            line-height: 1.6;
            color: #1B4332;
            box-sizing: border-box;

            /* INICIO DEL CONTADOR - Aquí se guardan los aciertos */
            counter-reset: aciertosTotales 0;
        }

        .exe-dg-wrapper * { box-sizing: border-box; }
        .exe-dg-wrapper p:empty { display: none; }

        /* Ocultar inputs pero mantenerlos accesibles para el cálculo */
        .exe-sr-only {
            position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px;
            overflow: hidden; clip: rect(0,0,0,0); border: 0;
        }

        /* ¡LA SUMA AUTOMÁTICA! Cada vez que se marca la clase correcta, suma 1 */
        .exe-is-correct:checked { counter-increment: aciertosTotales 1; }

        /* ===================================================
           2. CONTENEDOR PRINCIPAL Y ENCABEZADOS
           =================================================== */
        .exe-dg-card {
            background-color: #FFFFFF; max-width: 950px; width: 100%;
            border-radius: 20px; box-shadow: 0 12px 35px rgba(149, 213, 178, 0.25);
            position: relative; border: 1px solid #eefaf1; overflow: hidden;
        }

        .exe-dg-deco { height: 12px; background: linear-gradient(90deg, #95D5B2, #B7E4C7, #D8F3DC, #F8D7DA); }
        .exe-dg-header { text-align: center; padding: 40px 20px 20px; }
        .exe-dg-title { font-size: 2.3rem; color: #1B4332; margin: 0; font-weight: 800; text-transform: uppercase; }
        .exe-dg-title span { background-color: #eefaf1; padding: 5px 20px; border-radius: 10px; color: #2D6A4F; }
        .exe-dg-subtitle { font-size: 1.2rem; color: #B06572; margin: 15px 0 0; font-weight: 700; font-style: italic; }

        .exe-dg-instructions {
            font-size: 1.1rem; color: #40916C; text-align: center; background-color: #f3fbf5;
            padding: 20px; border-radius: 15px; margin: 0 30px 30px; border: 2px dashed #95D5B2;
        }

        /* ===================================================
           3. CUADRÍCULA DEL JUEGO (TARJETAS DINÁMICAS)
           =================================================== */
        .exe-dg-grid {
            display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
            gap: 25px; padding: 0 30px 30px;
        }

        .exe-dg-item {
            background-color: #ffffff; border: 3px solid #eefaf1; border-radius: 18px;
            padding: 20px; display: flex; flex-direction: column; align-items: center;
            box-shadow: 0 5px 15px rgba(0,0,0,0.03); transition: all 0.3s ease; position: relative;
        }
        .exe-dg-item:hover { transform: translateY(-5px); box-shadow: 0 10px 25px rgba(149, 213, 178, 0.2); }

        .exe-dg-name { font-size: 1.3rem; font-weight: 800; color: #1B4332; margin-bottom: 15px; text-align: center; order: 1; }

        /* El Emoji que reacciona */
        .exe-dg-emoji {
            font-size: 4rem; width: 100px; height: 100px; background-color: #fcfdfc;
            display: flex; justify-content: center; align-items: center; border-radius: 50%;
            border: 4px dashed #D8F3DC; margin-bottom: 20px; order: 3; transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
            user-select: none;
        }

        /* Botones de Selección */
        .exe-dg-options {
            display: flex; gap: 10px; width: 100%; justify-content: center; order: 4;
        }

        .exe-dg-btn {
            flex: 1; padding: 12px 10px; font-size: 0.95rem; font-weight: 700; text-align: center;
            border-radius: 12px; cursor: pointer; transition: all 0.2s ease; border: 2px solid transparent;
        }

        .exe-btn-real { background-color: #eefaf1; color: #2D6A4F; border-color: #B7E4C7; }
        .exe-btn-real:hover { background-color: #d8f3dc; transform: scale(1.05); }

        .exe-btn-chat { background-color: #fff0f3; color: #A05260; border-color: #f4c2c6; }
        .exe-btn-chat:hover { background-color: #f8d7da; transform: scale(1.05); }

        /* ===================================================
           4. MAGIA VISUAL: REACCIONES AL HACER CLIC
           =================================================== */
        /* Si selecciona Comida Real (Independiente de si es correcto o no) */
        .exe-is-real:checked ~ .exe-dg-options .exe-btn-real {
            background-color: #2D6A4F; color: #ffffff; border-color: #1B4332; box-shadow: 0 4px 10px rgba(45,106,79,0.3);
        }
        .exe-is-real:checked ~ .exe-dg-emoji {
            background-color: #eefaf1; border: 4px solid #95D5B2; transform: scale(1.15) rotate(-5deg); box-shadow: 0 8px 20px rgba(149, 213, 178, 0.4);
        }

        /* Si selecciona Comida Chatarra (Independiente de si es correcto o no) */
        .exe-is-chat:checked ~ .exe-dg-options .exe-btn-chat {
            background-color: #A05260; color: #ffffff; border-color: #5c2c35; box-shadow: 0 4px 10px rgba(160,82,96,0.3);
        }
        .exe-is-chat:checked ~ .exe-dg-emoji {
            background-color: #fff0f3; border: 4px solid #F8D7DA; transform: scale(1.15) rotate(5deg); box-shadow: 0 8px 20px rgba(248, 215, 218, 0.4);
        }

        /* ===================================================
           5. SISTEMA DE EVALUACIÓN Y RESULTADOS
           =================================================== */
        .exe-dg-submit {
            display: block; width: 100%; max-width: 320px; margin: 10px auto 40px;
            background-color: #F8D7DA; color: #A05260; font-size: 1.2rem; font-weight: 800;
            text-align: center; padding: 15px 25px; border: 3px solid #f4c2c6; border-radius: 30px;
            cursor: pointer; transition: all 0.2s ease; box-shadow: 0 5px 15px rgba(248, 215, 218, 0.4);
        }
        .exe-dg-submit:hover { background-color: #fce4ec; transform: translateY(-3px); }

        #exe-check-game { display: none; }

        /* Bloquear el juego al revisar */
        #exe-check-game:checked ~ .exe-dg-grid { pointer-events: none; opacity: 0.95; }
        #exe-check-game:checked ~ .exe-dg-submit { display: none; }

        /* Caja de Resultado Final */
        .exe-dg-result-box {
            display: none; text-align: center; margin: 0 30px 40px; padding: 30px;
            border-radius: 15px; background: #eefaf1; border: 4px dashed #95D5B2;
            animation: popIn 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        #exe-check-game:checked ~ .exe-dg-result-box { display: block; }

        /* IMPRIMIR LA NOTA MATEMÁTICA */
        .exe-score-number::after { content: counter(aciertosTotales); }

        /* Mensajes de Feedback por Tarjeta */
        .exe-feedback {
            display: none; width: 100%; text-align: center; font-weight: bold; font-size: 1rem;
            padding: 8px; border-radius: 10px; margin-top: 15px; order: 5;
        }

        #exe-check-game:checked ~ .exe-dg-grid .exe-dg-item .exe-is-correct:checked ~ .exe-correct-msg {
            display: block; background-color: #d4edda; color: #155724; border: 2px solid #28a745;
        }
        #exe-check-game:checked ~ .exe-dg-grid .exe-dg-item .exe-is-incorrect:checked ~ .exe-incorrect-msg {
            display: block; background-color: #f8d7da; color: #721c24; border: 2px solid #dc3545;
        }

        /* Iluminar tarjeta correcta/incorrecta */
        #exe-check-game:checked ~ .exe-dg-grid .exe-dg-item:has(.exe-is-correct:checked) { border-color: #28a745; }
        #exe-check-game:checked ~ .exe-dg-grid .exe-dg-item:has(.exe-is-incorrect:checked) { border-color: #dc3545; }

        @keyframes popIn {
            0% { opacity: 0; transform: scale(0.8); }
            100% { opacity: 1; transform: scale(1); }
        }

        @media (max-width: 768px) {
            .exe-dg-title { font-size: 1.8rem; }
            .exe-dg-grid { grid-template-columns: 1fr; padding: 0 15px 30px; }
            .exe-dg-instructions { margin: 0 15px 25px; }
        }
    </style>
<div class="exe-dg-wrapper">
<div class="exe-dg-card">
<div class="exe-dg-deco"><br /></div>
<div class="exe-bg-circle exe-circle-1"><br /></div>
