{"ideviceId":"idevice-1781023845480-qfp96pe5z","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<style>
        .exe-master-wrapper {
            background-color: #fffafb;
            padding: 30px 15px;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            line-height: 1.6;
            color: #5a7d65;
            box-sizing: border-box;
            counter-reset: notaFinal 0; 
        }

        .exe-master-wrapper * { box-sizing: border-box; }
        .exe-master-wrapper p:empty { display: none; }

        .exe-content-card {
            background-color: #FFFFFF;
            max-width: 900px;
            width: 100%;
            border-radius: 30px;
            box-shadow: 0 12px 35px rgba(255, 202, 212, 0.3);
            overflow: hidden;
            position: relative;
            border: 3px solid #ffcad4;
        }

        .exe-deco-top { height: 15px; background: linear-gradient(90deg, #ffcad4, #b7e4c7, #f48fb1, #95D5B2); }
        .exe-bg-circle { position: absolute; width: 200px; height: 200px; border-radius: 50%; opacity: 0.3; z-index: 0; }
        .exe-circle-1 { top: -80px; left: -80px; background-color: #b7e4c7; }
        .exe-circle-2 { bottom: -80px; right: -80px; background-color: #ffcad4; }

        .exe-header-section { text-align: center; padding: 40px 30px 20px; position: relative; z-index: 1; }
        .exe-emoji-header { font-size: 4.5rem; margin: 0 0 15px; text-align: center; }
        .exe-main-title { font-size: 2.2rem; color: #5a7d65; margin: 0; font-weight: 800; line-height: 1.2; }
        .exe-subtitle { font-size: 1.2rem; color: #f48fb1; margin: 10px 0 0; font-weight: 700; font-style: italic; }

        .exe-intro-text {
            font-size: 1.15rem; color: #5a7d65; text-align: center; background-color: #f8fcf9;
            padding: 20px; border-radius: 15px; margin: 0 40px 30px; border: 2px dashed #b7e4c7;
            position: relative; z-index: 1;
        }

        .exe-activity-box {
            background-color: transparent;
            margin: 0 40px 40px; position: relative; z-index: 1;
        }

        .exe-hidden-input {
            position: absolute;
            opacity: 0;
            width: 1px;
            height: 1px;
            z-index: -1;
            pointer-events: none;
        }

        .exe-q-correct:checked { counter-increment: notaFinal 1; }

        .exe-question-card {
            background-color: #ffffff; border: 2px solid #ffcad4; border-radius: 20px;
            padding: 25px; margin-bottom: 20px; transition: all 0.2s ease;
        }

        .exe-question-title { font-size: 1.1rem; color: #5a7d65; font-weight: 700; margin-top: 0; margin-bottom: 15px; }

        .exe-options-group { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; position: relative; }

        .exe-box-label {
            display: block; padding: 15px; background-color: #f8fcf9; text-align: center;
            border: 2px solid #b7e4c7; border-radius: 12px; cursor: pointer;
            font-size: 1.05rem; color: #5a7d65; transition: all 0.2s ease; user-select: none; font-weight: 600;
        }

        .exe-box-label:hover { background-color: #ffcad4; border-color: #f48fb1; }

        .exe-hidden-input:checked + .exe-box-label {
            background-color: #ffcad4; border-color: #f48fb1; color: #5a7d65; font-weight: bold; transform: scale(1.02);
            box-shadow: 0 4px 10px rgba(255, 202, 212, 0.4);
        }

        .exe-submit-btn {
            display: block; width: 100%; max-width: 320px; margin: 30px auto 0;
            background-color: #2d6a4f; color: #ffffff; font-size: 1.2rem; font-weight: 800;
            text-align: center; padding: 18px 25px; border: none; border-radius: 40px;
            cursor: pointer; transition: all 0.2s ease; box-shadow: 0 5px 15px rgba(45, 106, 79, 0.3);
        }
        .exe-submit-btn:hover { background-color: #1b4332; transform: translateY(-3px); }

        #exe-show-final-results:checked ~ .exe-submit-btn,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-submit-btn { display: none; }

        #exe-show-final-results:checked ~ .exe-question-card,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-question-card { pointer-events: none; opacity: 0.95; border-color: #e2e8e4; }

        .exe-result-box {
            display: none; text-align: center; margin-top: 30px; padding: 30px;
            border-radius: 20px; background: #f8fcf9; border: 4px dashed #95D5B2; animation: fadeInResult 0.8s ease;
        }
        #exe-show-final-results:checked ~ .exe-result-box,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-result-box { display: block; }

        .exe-css-score::after { content: counter(notaFinal); }

        #exe-show-final-results:checked ~ .exe-question-card .exe-q-correct:checked + .exe-box-label,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-q-correct:checked + .exe-box-label {
            background-color: #d4edda; border-color: #28a745; color: #155724; transform: scale(1); box-shadow: none;
        }
        #exe-show-final-results:checked ~ .exe-question-card .exe-q-correct:checked + .exe-box-label::after,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-q-correct:checked + .exe-box-label::after {
            content: " ✅ Correcto"; display: block; font-size: 0.9rem; margin-top: 5px; color: #155724; font-weight: normal;
        }

        #exe-show-final-results:checked ~ .exe-question-card .exe-q-incorrect:checked + .exe-box-label,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-q-incorrect:checked + .exe-box-label {
            background-color: #f8d7da; border-color: #dc3545; color: #721c24; transform: scale(1); box-shadow: none;
        }
        #exe-show-final-results:checked ~ .exe-question-card .exe-q-incorrect:checked + .exe-box-label::after,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-q-incorrect:checked + .exe-box-label::after {
            content: " ❌ Incorrecto"; display: block; font-size: 0.9rem; margin-top: 5px; color: #721c24; font-weight: normal;
        }

        #exe-show-final-results:checked ~ .exe-question-card .exe-q-correct + .exe-box-label,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-q-correct + .exe-box-label {
            border-left: 5px solid #28a745;
        }

        .exe-feedback-text {
            display: none; margin-top: 15px; font-size: 0.95rem; color: #5a7d65;
            background: #fff5f7; padding: 12px; border-radius: 10px; border-left: 4px solid #ffcad4; font-style: italic;
        }
        #exe-show-final-results:checked ~ .exe-question-card .exe-feedback-text,
        .exe-master-wrapper:has(#exe-show-final-results:checked) .exe-feedback-text { display: block; animation: fadeInResult 0.5s ease; }

        @keyframes fadeInResult {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 768px) {
            .exe-main-title { font-size: 1.8rem; }
            .exe-activity-box, .exe-intro-text { margin-left: 15px; margin-right: 15px; padding: 20px; }
            .exe-options-group { grid-template-columns: 1fr; }
        }
