<div class="exe-options-group"><input type="radio" id="exe-q4-a" name="exe-q4" class="exe-hidden-input exe-q-correct" /> <label for="exe-q4-a" class="exe-box-label">A) Energía sostenida</label> <input type="radio" id="exe-q4-b" name="exe-q4" class="exe-hidden-input exe-q-incorrect" /> <label for="exe-q4-b" class="exe-box-label">B) Azúcar</label></div>
