<div class="exe-options-group"><input type="radio" id="exe-q6-a" name="exe-q6" class="exe-hidden-input exe-q-incorrect" /> <label for="exe-q6-a" class="exe-box-label">A) Sí</label> <input type="radio" id="exe-q6-b" name="exe-q6" class="exe-hidden-input exe-q-correct" /> <label for="exe-q6-b" class="exe-box-label">B) No</label></div>
