<div class="exe-options-group"><input type="radio" id="exe-q7-a" name="exe-q7" class="exe-hidden-input exe-q-correct" /> <label for="exe-q7-a" class="exe-box-label">A) Comida real</label> <input type="radio" id="exe-q7-b" name="exe-q7" class="exe-hidden-input exe-q-incorrect" /> <label for="exe-q7-b" class="exe-box-label">B) Ultraprocesados</label></div>
