            background-color: #fcfdfc;
            padding: 30px 15px;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            line-height: 1.6;
            color: #1B4332;
            box-sizing: border-box;
        }

        .exe-master-wrapper * { box-sizing: border-box; }
        .exe-master-wrapper p:empty { display: none; }

        .exe-content-card {
            background-color: #FFFFFF;
            max-width: 900px;
            width: 100%;
            border-radius: 20px;
            box-shadow: 0 12px 35px rgba(149, 213, 178, 0.25);
            overflow: hidden;
            position: relative;
            border: 1px solid #eefaf1;
        }

        .exe-deco-top {
            height: 12px;
            background: linear-gradient(90deg, #95D5B2, #B7E4C7, #D8F3DC, #F8D7DA);
        }

        .exe-bg-circle {
            position: absolute; width: 150px; height: 150px; border-radius: 50%; opacity: 0.4; z-index: 0;
        }
        .exe-circle-1 { top: -50px; left: -50px; background-color: #D8F3DC; }
        .exe-circle-2 { bottom: -50px; right: -60px; background-color: #F8D7DA; }

        .exe-header-section {
            text-align: center;
            padding: 40px 30px 20px;
            position: relative;
            z-index: 1;
        }

        .exe-main-title {
            font-size: 2.2rem; color: #1B4332; margin: 0; font-weight: 800; line-height: 1.2; text-transform: uppercase;
        }

        .exe-main-title span {
            background-color: #eefaf1; padding: 5px 20px; border-radius: 10px; color: #2D6A4F;
        }

        .exe-intro-text {
            font-size: 1.15rem; color: #40916C; text-align: justify; background-color: #f3fbf5;
            padding: 25px; border-radius: 15px; margin: 0 40px 30px; border-left: 5px solid #F8D7DA;
            box-shadow: 0 4px 10px rgba(0,0,0,0.02); position: relative; z-index: 1;
        }

        /* ===================================================
           2. GRÁFICO DE OCTÓGONOS (PURO CSS)
           =================================================== */
        .exe-graphic-container {
            background-color: #fffaf0; border: 3px dashed #ffe082; border-radius: 20px;
            margin: 0 40px 40px; padding: 30px 20px; display: flex; align-items: center;
            justify-content: center; flex-wrap: wrap; gap: 20px; position: relative; z-index: 1;
        }

        .exe-octagons-box {
            display: flex; gap: 15px; flex-wrap: wrap; justify-content: center;
            background: #ffffff; padding: 20px; border-radius: 15px; border: 2px solid #e0e0e0;
        }

        .exe-octagon-group { display: flex; flex-direction: column; align-items: center; gap: 10px; }

        .exe-octagon {
            width: 80px; height: 80px; background-color: #000000;
            clip-path: polygon(30% 0%, 70% 0%, 100% 30%, 100% 70%, 70% 100%, 30% 100%, 0% 70%, 0% 30%);
            display: flex; justify-content: center; align-items: center; padding: 3px;
        }

        .exe-octagon-inner {
            width: 100%; height: 100%; background-color: #000000; border: 1px solid #ffffff;
            clip-path: polygon(30% 0%, 70% 0%, 100% 30%, 100% 70%, 70% 100%, 30% 100%, 0% 70%, 0% 30%);
            display: flex; justify-content: center; align-items: center;
            color: #ffffff; font-size: 0.65rem; font-weight: bold; text-align: center; line-height: 1.2;
        }

        .exe-icon-symbol {
            font-size: 2rem; background: #fcfdfc; width: 50px; height: 50px;
            display: flex; justify-content: center; align-items: center; border-radius: 50%;
        }

        .exe-down-arrow { color: #757575; font-size: 1.2rem; }
        .exe-consequence { display: flex; align-items: center; gap: 15px; }
        .exe-right-arrow { color: #9c27b0; font-size: 3rem; font-weight: bold; }

        .exe-stomach-icon {
            font-size: 5rem; background: #f3e5f5; padding: 15px; border-radius: 50%;
            border: 4px dashed #ce93d8; animation: pulseStomach 2s infinite;
        }

        @keyframes pulseStomach {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }

        /* ===================================================
           3. SISTEMA DE EVALUACIÓN INTERACTIVA (100% CSS)
           =================================================== */
        .exe-activity-box {
            background-color: #ffffff; border: 3px solid #95D5B2; border-radius: 15px;
            margin: 0 40px 40px; padding: 25px; position: relative; z-index: 1;
        }

        .exe-cards-container h3 {
            color: #1B4332; margin-top: 0; display: flex; align-items: center; gap: 10px;
            border-bottom: 2px dashed #B7E4C7; padding-bottom: 10px; font-size: 1.5rem;
        }

        .exe-hidden-input { display: none; }

        .exe-question-card {
            background-color: #fcfdfc; border: 2px solid #eefaf1; border-radius: 12px;
            padding: 20px; margin-bottom: 20px; transition: all 0.2s ease;
        }

        .exe-question-title {
            font-size: 1.1rem; color: #2D6A4F; font-weight: 700; margin-top: 0; margin-bottom: 15px; text-align: justify;
        }

        .exe-options-group { display: grid; grid-template-columns: 1fr; gap: 12px; }

        .exe-box-label {
            display: block; padding: 12px 15px; background-color: #ffffff;
            border: 2px solid #D8F3DC; border-radius: 10px; cursor: pointer;
            font-size: 1.05rem; color: #40916C; transition: all 0.2s ease;
        }

        .exe-box-label:hover { background-color: #f3fbf5; border-color: #95D5B2; }

        /* Colores al seleccionar (Antes de enviar) */
        #exe-q1-a:checked ~ .exe-cards-container .label-q1-a,
        #exe-q1-b:checked ~ .exe-cards-container .label-q1-b,
        #exe-q2-a:checked ~ .exe-cards-container .label-q2-a,
        #exe-q2-b:checked ~ .exe-cards-container .label-q2-b,
        #exe-q3-a:checked ~ .exe-cards-container .label-q3-a,
        #exe-q3-b:checked ~ .exe-cards-container .label-q3-b {
            background-color: #95D5B2; border-color: #2D6A4F; color: #1B4332; font-weight: bold;
        }

        /* Botón Verificar */
        .exe-submit-btn {
            display: block; width: 100%; max-width: 300px; margin: 30px auto 0;
            background-color: #F8D7DA; color: #A05260; font-size: 1.1rem; font-weight: 800;
            text-align: center; padding: 12px 25px; border: 2px solid #f4c2c6; border-radius: 30px;
            cursor: pointer; transition: all 0.2s ease;
        }
        .exe-submit-btn:hover { background-color: #fce4ec; transform: translateY(-2px); }

        /* Al hacer clic en Verificar */
        #exe-show-final-results:checked ~ .exe-cards-container { pointer-events: none; opacity: 0.9; }
        #exe-show-final-results:checked ~ .exe-submit-btn { display: none; }

        .exe-result-box {
            display: none; text-align: center; margin-top: 20px; padding: 20px;
            border-radius: 12px; background: #eefaf1; border: 2px dashed #95D5B2; animation: fadeInResult 0.8s ease;
        }
        #exe-show-final-results:checked ~ .exe-result-box { display: block; }

        /* ===================================================
           NUEVO SISTEMA DE CÁLCULO DE NOTAS (A PRUEBA DE FALLOS)
           =================================================== */
        .s-0 { display: inline; }
        .s-1, .s-2, .s-3 { display: none; }

        /* Si hay EXACTAMENTE 1 correcta */
        #exe-q1-b:checked ~ .exe-result-box .s-0,
        #exe-q2-a:checked ~ .exe-result-box .s-0,
        #exe-q3-b:checked ~ .exe-result-box .s-0 { display: none; }

        #exe-q1-b:checked ~ .exe-result-box .s-1,
        #exe-q2-a:checked ~ .exe-result-box .s-1,
        #exe-q3-b:checked ~ .exe-result-box .s-1 { display: inline; }

        /* Si hay EXACTAMENTE 2 correctas (Sobrescribe la de 1) */
        #exe-q1-b:checked ~ #exe-q2-a:checked ~ .exe-result-box .s-1,
        #exe-q1-b:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-1,
        #exe-q2-a:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-1 { display: none; }

        #exe-q1-b:checked ~ #exe-q2-a:checked ~ .exe-result-box .s-2,
        #exe-q1-b:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-2,
        #exe-q2-a:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-2 { display: inline; }

        /* Si hay EXACTAMENTE 3 correctas (Sobrescribe la de 2) */
        #exe-q1-b:checked ~ #exe-q2-a:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-2 { display: none; }
        #exe-q1-b:checked ~ #exe-q2-a:checked ~ #exe-q3-b:checked ~ .exe-result-box .s-3 { display: inline; }


        /* PINTAR RESPUESTAS CORRECTAS E INCORRECTAS */
        /* Correctas */
        #exe-show-final-results:checked ~ #exe-q1-b:checked ~ .exe-cards-container .label-q1-b,
        #exe-show-final-results:checked ~ #exe-q2-a:checked ~ .exe-cards-container .label-q2-a,
        #exe-show-final-results:checked ~ #exe-q3-b:checked ~ .exe-cards-container .label-q3-b {
            background-color: #d4edda; border-color: #28a745; color: #155724;
        }
        #exe-show-final-results:checked ~ #exe-q1-b:checked ~ .exe-cards-container .label-q1-b::after,
        #exe-show-final-results:checked ~ #exe-q2-a:checked ~ .exe-cards-container .label-q2-a::after,
        #exe-show-final-results:checked ~ #exe-q3-b:checked ~ .exe-cards-container .label-q3-b::after {
            content: " ✅ ¡Correcto!"; display: block; font-size: 0.9rem; margin-top: 5px; font-weight: normal;
        }

        /* Incorrectas */
        #exe-show-final-results:checked ~ #exe-q1-a:checked ~ .exe-cards-container .label-q1-a,
        #exe-show-final-results:checked ~ #exe-q2-b:checked ~ .exe-cards-container .label-q2-b,
        #exe-show-final-results:checked ~ #exe-q3-a:checked ~ .exe-cards-container .label-q3-a {
            background-color: #f8d7da; border-color: #dc3545; color: #721c24;
        }
        #exe-show-final-results:checked ~ #exe-q1-a:checked ~ .exe-cards-container .label-q1-a::after,
        #exe-show-final-results:checked ~ #exe-q2-b:checked ~ .exe-cards-container .label-q2-b::after,
        #exe-show-final-results:checked ~ #exe-q3-a:checked ~ .exe-cards-container .label-q3-a::after {
            content: " ❌ Incorrecto"; display: block; font-size: 0.9rem; margin-top: 5px; font-weight: normal;
        }

        /* Subrayar la correcta si el usuario marcó la incorrecta */
        #exe-show-final-results:checked ~ .exe-cards-container .label-q1-b,
        #exe-show-final-results:checked ~ .exe-cards-container .label-q2-a,
        #exe-show-final-results:checked ~ .exe-cards-container .label-q3-b {
            border-left: 5px solid #28a745;
        }

        @keyframes fadeInResult {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 768px) {
            .exe-main-title { font-size: 1.8rem; }
            .exe-graphic-container, .exe-activity-box, .exe-intro-text { margin-left: 15px; margin-right: 15px; padding: 20px; }
            .exe-consequence { flex-direction: column; }
            .exe-right-arrow { transform: rotate(90deg); }
        }
