        /* ===================================================
           1. ESTILOS GLOBALES Y INICIALIZACIÓN DEL CONTADOR
           =================================================== */
        .exe-master-wrapper {
            background-color: #fcfdfc;
            padding: 30px 15px;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            line-height: 1.6;
            color: #1B4332;
            box-sizing: border-box;

            /* Se inicializa el contador matemático en 0 */
            counter-reset: puntajeTotal 0;
        }

        .exe-master-wrapper * { box-sizing: border-box; }

        .exe-content-card {
            background-color: #FFFFFF;
            max-width: 900px;
            width: 100%;
            border-radius: 20px;
            box-shadow: 0 12px 35px rgba(149, 213, 178, 0.25);
            overflow: hidden;
            position: relative;
            border: 1px solid #eefaf1;
        }

        .exe-deco-top { height: 12px; background: linear-gradient(90deg, #95D5B2, #B7E4C7, #D8F3DC, #F8D7DA); }
        .exe-bg-circle { position: absolute; width: 150px; height: 150px; border-radius: 50%; opacity: 0.4; z-index: 0; }
        .exe-circle-1 { top: -50px; left: -50px; background-color: #D8F3DC; }
        .exe-circle-2 { bottom: -50px; right: -60px; background-color: #F8D7DA; }

        .exe-header-section { text-align: center; padding: 40px 30px 20px; position: relative; z-index: 1; }
        .exe-main-title { font-size: 2.2rem; color: #1B4332; margin: 0; font-weight: 800; text-transform: uppercase; }
        .exe-main-title span { background-color: #eefaf1; padding: 5px 20px; border-radius: 10px; color: #2D6A4F; }
        .exe-subtitle { font-size: 1.3rem; color: #B06572; margin: 15px 0 0; font-weight: 700; font-style: italic; }

        .exe-intro-text {
            font-size: 1.15rem; color: #40916C; text-align: center; background-color: #f3fbf5;
            padding: 20px; border-radius: 15px; margin: 0 40px 30px; border: 2px dashed #95D5B2;
            position: relative; z-index: 1;
        }

        /* ===================================================
           2. INTERFAZ DE RELACIÓN DE CONCEPTOS
           =================================================== */
        .exe-match-container {
            margin: 0 40px 40px;
            position: relative;
            z-index: 1;
            display: flex;
            flex-direction: column;
            gap: 20px;
        }

        .exe-match-row {
            background-color: #ffffff;
            border: 2px solid #D8F3DC;
            border-radius: 12px;
            padding: 20px;
            display: flex;
            flex-direction: column;
            gap: 12px;
            transition: all 0.2s ease;
        }

        .exe-def-text {
            font-size: 1.05rem;
            color: #2D6A4F;
            text-align: justify;
            line-height: 1.5;
        }

        .exe-select-concept {
            width: 100%;
            max-width: 320px;
            padding: 10px 15px;
            font-size: 1rem;
            border: 2px solid #95D5B2;
            border-radius: 8px;
            color: #1B4332;
            background-color: #fcfdfc;
            cursor: pointer;
            outline: none;
            font-weight: 600;
        }

        .exe-select-concept:focus {
            border-color: #2D6A4F;
            background-color: #ffffff;
        }

        /* LÓGICA DE SUMA MATEMÁTICA EN CSS:
           Cada vez que una fila contenga un elemento con la respuesta correcta válida (value="correcto"),
           el contador "puntajeTotal" incrementará automáticamente en 1. */
        .exe-match-row:has(.exe-select-correct option[value="correcto"]:checked) {
            counter-increment: puntajeTotal 1;
        }

        /* ===================================================
           3. SISTEMA DE REVISIÓN Y BOTÓN DE ACCIÓN
           =================================================== */
        .exe-check-btn {
            display: block; width: 100%; max-width: 300px; margin: 30px auto 0;
            background-color: #F8D7DA; color: #A05260; font-size: 1.1rem; font-weight: 800;
            text-align: center; padding: 15px 25px; border: 2px solid #f4c2c6; border-radius: 30px;
            cursor: pointer; transition: all 0.2s ease; box-shadow: 0 5px 15px rgba(248, 215, 218, 0.4);
            position: relative; z-index: 1; user-select: none;
        }
        .exe-check-btn:hover { background-color: #fce4ec; transform: translateY(-3px); }

        #exe-trigger-results { display: none; }

        /* Bloqueo de interacción post-evaluación */
        #exe-trigger-results:checked ~ .exe-match-container { pointer-events: none; }
        #exe-trigger-results:checked ~ .exe-check-btn { display: none; }

        /* REVELACIÓN DEL PANEL DE RESULTADOS CON LA NOTA SUMADA */
        .exe-score-box {
            display: none; text-align: center; margin: 30px 40px 40px; padding: 30px;
            border-radius: 12px; background: #eefaf1; border: 3px dashed #95D5B2;
            position: relative; z-index: 1; animation: fadeInUp 0.5s ease;
        }
        #exe-trigger-results:checked ~ .exe-score-box { display: block; }

        /* Inserta el valor final acumulado del contador en el HTML */
        .exe-final-score::after {
            content: counter(puntajeTotal);
        }

        /* RESPUESTAS CORRECTAS (VISUALIZACIÓN COGNITIVA) */
        #exe-trigger-results:checked ~ .exe-match-container .exe-match-row:has(.exe-select-correct option[value="correcto"]:checked) {
            border-color: #28a745; background-color: #d4edda;
        }
        #exe-trigger-results:checked ~ .exe-match-container .exe-match-row:has(.exe-select-correct option[value="correcto"]:checked) .exe-select-concept {
            border-color: #28a745; background-color: #ffffff; color: #155724;
        }

        /* RESPUESTAS INCORRECTAS O VACÍAS */
        #exe-trigger-results:checked ~ .exe-match-container .exe-match-row:not(:has(.exe-select-correct option[value="correcto"]:checked)) {
            border-color: #dc3545; background-color: #f8d7da;
        }
        #exe-trigger-results:checked ~ .exe-match-container .exe-match-row:not(:has(.exe-select-correct option[value="correcto"]:checked)) .exe-select-concept {
            border-color: #dc3545; background-color: #ffffff; color: #721c24;
        }

        /* Texto de apoyo pedagógico oculto que se revela al final */
        .exe-correct-answer-text { display: none; font-size: 0.95rem; font-weight: bold; color: #2D6A4F; margin-top: 5px; }
        #exe-trigger-results:checked ~ .exe-match-container .exe-correct-answer-text { display: block; }

        @keyframes fadeInUp {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 768px) {
            .exe-main-title { font-size: 1.8rem; }
            .exe-match-container, .exe-intro-text, .exe-score-box { margin-left: 15px; margin-right: 15px; padding: 15px; }
        }
