        /* ===================================================
           1. ESTILOS GLOBALES Y CONTADOR PROTEGIDO
           =================================================== */
        .exe-master-wrapper {
            background-color: #fcfdfc;
            padding: 30px 15px;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            line-height: 1.6;
            color: #1B4332;
            box-sizing: border-box;

            /* Iniciamos el contador de logros */
            counter-reset: totalLogros 0; 
        }

        .exe-master-wrapper * { box-sizing: border-box; }
        .exe-master-wrapper p:empty { display: none; }

        .exe-content-card {
            background-color: #FFFFFF;
            max-width: 900px;
            width: 100%;
            border-radius: 20px;
            box-shadow: 0 12px 35px rgba(149, 213, 178, 0.25);
            overflow: hidden;
            position: relative;
            border: 1px solid #eefaf1;
        }

        .exe-deco-top { height: 12px; background: linear-gradient(90deg, #95D5B2, #B7E4C7, #D8F3DC, #F8D7DA); }
        .exe-bg-circle { position: absolute; width: 150px; height: 150px; border-radius: 50%; opacity: 0.4; z-index: 0; }
        .exe-circle-1 { top: -50px; left: -50px; background-color: #D8F3DC; }
        .exe-circle-2 { bottom: -50px; right: -60px; background-color: #F8D7DA; }

        .exe-header-section { text-align: center; padding: 40px 30px 20px; position: relative; z-index: 1; }
        .exe-main-title { font-size: 2.2rem; color: #1B4332; margin: 0; font-weight: 800; text-transform: uppercase; }
        .exe-main-title span { background-color: #eefaf1; padding: 5px 20px; border-radius: 10px; color: #2D6A4F; }
        .exe-subtitle { font-size: 1.3rem; color: #B06572; margin: 15px 0 0; font-weight: 700; font-style: italic; }

        .exe-intro-text {
            font-size: 1.15rem; color: #40916C; text-align: center; background-color: #f3fbf5;
            padding: 20px; border-radius: 15px; margin: 0 40px 30px; border: 2px dashed #95D5B2;
            position: relative; z-index: 1; box-shadow: 0 4px 10px rgba(0,0,0,0.02);
        }

        /* ===================================================
           2. DISEÑO DE LA TABLA DE COTEJO
           =================================================== */
        .exe-checklist-container {
            margin: 0 40px 40px;
            position: relative;
            z-index: 1;
            overflow-x: auto; /* Para que no se rompa en celulares */
        }

        .exe-checklist-table {
            width: 100%;
            border-collapse: collapse;
            background-color: #ffffff;
            border-radius: 15px;
            overflow: hidden;
            border: 2px solid #B7E4C7;
            box-shadow: 0 8px 20px rgba(149, 213, 178, 0.15);
        }

        .exe-checklist-table th {
            background-color: #95D5B2;
            color: #1B4332;
            font-size: 1.15rem;
            padding: 15px;
            text-align: center;
            font-weight: 800;
            border-bottom: 3px solid #2D6A4F;
        }

        .exe-checklist-table th:first-child { text-align: left; }

        .exe-checklist-table td {
            padding: 15px;
            border-bottom: 1px solid #D8F3DC;
            color: #2D6A4F;
            font-size: 1.05rem;
            vertical-align: middle;
        }

        .exe-checklist-table tr:last-child td { border-bottom: none; }
        .exe-checklist-table tr:hover { background-color: #fcfdfc; }

        /* Iconos de las viñetas en la tabla */
        .exe-crit-icon { margin-right: 10px; font-size: 1.2rem; }

        /* ===================================================
           3. BOTONES INTERACTIVOS (RADIO BUTTONS CUSTOM)
           =================================================== */
        .exe-check-cell { text-align: center; width: 80px; }

        .exe-hidden-radio {
            position: absolute; opacity: 0; width: 1px; height: 1px; z-index: -1; pointer-events: none;
        }

        .exe-radio-label {
            display: inline-flex;
            justify-content: center;
            align-items: center;
            width: 40px;
            height: 40px;
            background-color: #f3fbf5;
            border: 2px solid #D8F3DC;
            border-radius: 10px;
            cursor: pointer;
            transition: all 0.2s ease;
            font-size: 1.2rem;
            user-select: none;
        }

        .exe-radio-label:hover { transform: scale(1.1); box-shadow: 0 4px 8px rgba(0,0,0,0.1); }

        /* Estado seleccionado para "SÍ" (Verde) */
        .exe-check-si:checked + .exe-radio-label {
            background-color: #d4edda; border-color: #28a745; box-shadow: inset 0 0 0 2px #ffffff;
        }

        /* Estado seleccionado para "NO" (Rojo) */
        .exe-check-no:checked + .exe-radio-label {
            background-color: #f8d7da; border-color: #dc3545; box-shadow: inset 0 0 0 2px #ffffff;
        }

        /* ¡LA MAGIA DE LA SUMA! */
        .exe-check-si:checked { counter-increment: totalLogros 1; }

        /* ===================================================
           4. BOTÓN DE RESULTADO Y CAJA FINAL
           =================================================== */
        .exe-submit-btn {
            display: block; width: 100%; max-width: 320px; margin: 30px auto 0;
            background-color: #F8D7DA; color: #A05260; font-size: 1.1rem; font-weight: 800;
            text-align: center; padding: 15px 25px; border: 2px solid #f4c2c6; border-radius: 30px;
            cursor: pointer; transition: all 0.2s ease; box-shadow: 0 5px 15px rgba(248, 215, 218, 0.4);
            position: relative; z-index: 1; user-select: none;
        }
        .exe-submit-btn:hover { background-color: #fce4ec; transform: translateY(-3px); }

        #exe-trigger-cotejo { display: none; }

        #exe-trigger-cotejo:checked ~ .exe-checklist-container { pointer-events: none; opacity: 0.9; }
        #exe-trigger-cotejo:checked ~ .exe-submit-btn { display: none; }

        .exe-result-box {
            display: none; text-align: center; margin: 30px 40px 40px; padding: 30px;
            border-radius: 15px; background: #eefaf1; border: 3px dashed #95D5B2;
            position: relative; z-index: 1; animation: fadeInUp 0.8s ease;
        }

        #exe-trigger-cotejo:checked ~ .exe-result-box { display: block; }

        /* Impresión del contador CSS */
        .exe-css-score::after { content: counter(totalLogros); }

        @keyframes fadeInUp {
            from { opacity: 0; transform: translateY(15px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 768px) {
            .exe-main-title { font-size: 1.8rem; }
            .exe-checklist-container, .exe-intro-text { margin-left: 10px; margin-right: 10px; padding: 15px; }
            .exe-checklist-table th, .exe-checklist-table td { padding: 10px; font-size: 0.95rem; }
            .exe-radio-label { width: 32px; height: 32px; font-size: 1rem; }
        }
    </style>
